// shadcn
import { Button } from "@/components/ui/button";

// assets
import { GalleryVerticalEndIcon, SunMediumIcon } from "lucide-react";

// constants
const plans = [
  {
    id: 1,
    icon: SunMediumIcon,
    name: "Basic Plan",
    price: 49,
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led way.",
    featured: true
  },
  {
    id: 2,
    icon: GalleryVerticalEndIcon,
    name: "Advanced Plan",
    price: 99,
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led way.",
    featured: false
  }
];

//  ------------------------------ | PRICING 2 | ------------------------------  //

export default function Pricing2() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14 flex flex-col gap-3">
          <h2 className="text-foreground">Choose Pricing Plans</h2>
          <p className="text-muted-foreground max-w-lg mx-auto">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Two-column split with divider */}
        <div className="grid grid-cols-1 sm:grid-cols-2 divide-y sm:divide-y-0 sm:divide-x divide-border">
          {plans.map((plan) => {
            const Icon = plan.icon;
            return (
              <div key={plan.id} className="flex flex-col gap-6 px-8 py-4">
                {/* Icon */}
                <Icon className="size-13 text-primary" strokeWidth={1.5} />

                {/* Plan name */}
                <h4>{plan.name}</h4>

                {/* Price */}
                <div className="flex items-end gap-1.5">
                  <span className="text-5xl font-bold text-primary">
                    ${plan.price}
                  </span>
                  <span className="text-muted-foreground text-md mb-1">
                    /per month
                  </span>
                </div>

                {/* Description */}
                <p className="text-muted-foreground text-md">
                  {plan.description}
                </p>

                {/* CTA */}
                <div>
                  <Button
                    className={
                      plan.featured
                        ? "bg-primary text-primary-foreground"
                        : "bg-transparent border border-primary text-primary hover:bg-primary hover:text-primary-foreground"
                    }
                    variant={plan.featured ? "default" : "outline"}
                  >
                    Get Started
                  </Button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
